// 映射定义，将ANTLR的tokenTypeName映射到clang的格式
std::unordered_map<std::string, std::string> tokenTypeMapping = {
  { "Void", "void" },
  { "Int", "int" },
  { "Return", "return" },
  { "If", "if" },
  { "Else", "else" },
  { "While", "while" },
  { "Break", "break" },
  { "Continue", "continue" },
  { "Identifier", "identifier" },
  { "LeftParen", "l_paren" },
  { "RightParen", "r_paren" },
  { "RightBrace", "r_brace" },
  { "LeftBrace", "l_brace" },
  { "LeftBracket", "l_square" },
  { "RightBracket", "r_square" },
  { "Constant", "numeric_constant" },
  { "Semi", "semi" },
  { "EOF", "eof" },
  { "Equal", "equal" },
  { "EqualEqual", "equalequal" },
  { "NotEqual", "exclaim_equal" },
  { "Less", "less" },
  { "Greater", "greater" },
  { "LessEqual", "lessequal" },
  { "GreaterEqual", "greaterequal" },
  { "Plus", "plus" },
  { "Minus", "minus" },
  { "Star", "star" },
  { "Slash", "slash" },
  { "Percent", "percent" },
  { "Exclaim", "exclaim" },
  { "AmpAmp", "ampamp" },
  { "PipePipe", "pipepipe" },
  { "Amp", "amp" },
  { "Pipe", "pipe" },
  { "Comma", "comma" },
};

// Global state for tracking file/line/column from line directives
struct LocationState {
  std::string currentFile;
  int currentLine = 1;
  int currentColumn = 1;
  bool atLineStart = true;
  bool hasLeadingSpace = false;
};

static LocationState g_loc;

// Parse line directive and update location state
// Returns true if the line is a line directive
bool parseLineDirective(const std::string& line) {
  // Match: # number "filename" [flags]
  std::regex re(R"(^\s*#\s*(\d+)\s+"([^"]*)".*)", std::regex::ECMAScript);
  std::smatch match;
  if (std::regex_match(line, match, re)) {
    g_loc.currentLine = std::stoi(match[1].str());
    g_loc.currentFile = match[2].str();
    g_loc.currentColumn = 1;
    g_loc.atLineStart = true;
    g_loc.hasLeadingSpace = false;
    return true;
  }
  return false;
}

void
print_token(const antlr4::Token* token,
            const antlr4::CommonTokenStream& tokens,
            std::ofstream& outFile,
            const antlr4::Lexer& lexer)
{
  auto& vocabulary = lexer.getVocabulary();

  auto tokenTypeName =
    std::string(vocabulary.getSymbolicName(token->getType()));

  if (tokenTypeName.empty())
    tokenTypeName = "<UNKNOWN>"; // 处理可能的空字符串情况

  if (tokenTypeMapping.find(tokenTypeName) != tokenTypeMapping.end()) {
    tokenTypeName = tokenTypeMapping[tokenTypeName];
  }

  // Build location info
  std::string locInfo = " Loc=<" + g_loc.currentFile + ":" +
                          std::to_string(g_loc.currentLine) + ":" +
                          std::to_string(g_loc.currentColumn) + ">";

  bool startOfLine = g_loc.atLineStart;
  bool leadingSpace = g_loc.hasLeadingSpace;

  if (token->getText() != "<EOF>")
    outFile << tokenTypeName << " '" << token->getText() << "'";
  else
    outFile << tokenTypeName << " '"
            << "'";
  if (startOfLine)
    outFile << "\t [StartOfLine]";
  if (leadingSpace)
    outFile << " [LeadingSpace]";
  outFile << locInfo << std::endl;

  // Update location state for next token
  g_loc.atLineStart = false;
  g_loc.hasLeadingSpace = false;
  g_loc.currentColumn += token->getText().length();
}

int
main(int argc, char* argv[])
{
  if (argc != 3) {
    std::cout << "Usage: " << argv[0] << " <input> <output>\n";
    return -1;
  }

