  // Build a map of token index to location info
  // We need to process line directives to know the actual source location
  // But ANTLR handles tokenization, so we need a different approach
  // Let's re-read the file and track line directives

  // Reset file
  inFile.close();
  inFile.open(argv[1]);

  antlr4::ANTLRInputStream input(inFile);
  SYsULexer lexer(&input);

  antlr4::CommonTokenStream tokens(&lexer);
  tokens.fill();

  // Process tokens and track locations
