  inFile.open(argv[1]);
  std::string rawContent((std::istreambuf_iterator<char>(inFile)),
                          std::istreambuf_iterator<char>());
  inFile.close();

  // Parse line directives from raw content
  // Build a mapping from physical line to (file, line) info
  std::vector<std::pair<std::string, int>> lineMap;
  std::string currentFile = "";
  int currentLine = 1;

  size_t pos = 0;
  int physLine = 1;
  while (pos < rawContent.length()) {
    // Find end of current line
    size_t lineEnd = rawContent.find('\n', pos);
    if (lineEnd == std::string::npos) {
      lineEnd = rawContent.length();
    }
    std::string currentLineStr = rawContent.substr(pos, lineEnd - pos);
    // Remove trailing \r
    if (!currentLineStr.empty() && currentLineStr.back() == '\r') {
      currentLineStr.pop_back();
    }

    // Check if this is a line directive
    std::regex re2(R"(^\s*#\s*(\d+)\s+"([^"]*)".*)", std::regex::ECMAScript);
    std::smatch match2;
    if (std::regex_match(currentLineStr, match2, re2)) {
      currentLine = std::stoi(match2[1].str());
      currentFile = match2[2].str();
    }

    lineMap.push_back({currentFile, currentLine});

    currentLine++;
    pos = lineEnd + 1;
  }

  // Now process tokens with correct location info
  g_loc.currentFile = "";
  g_loc.currentLine = 1;
  g_loc.currentColumn = 1;
  g_loc.atLineStart = true;
  g_loc.hasLeadingSpace = false;

  // We need to track the actual source position from the raw content
  // ANTLR gives us line and column in the preprocessed file
  // We need to map that to the actual source location

  // For simplicity, let's track position in raw content
  size_t rawPos = 0;
  int rawLine = 1;
  int rawCol = 1;
  bool atLineStart = true;
  bool hasLeadingSpace = false;

  // Re-read raw content for position tracking
  inFile.open(argv[1]);
  std::string rawContent2((std::istreambuf_iterator<char>(inFile)),
                           std::istreambuf_iterator<char>());
  inFile.close();

  currentFile = "";
  currentLine = 1;

  for (auto&& token : tokens.getTokens()) {
    int tokenLine = token->getLine();
    int tokenCol = token->getCharPositionInLine() + 1;

    // Find the actual source location for this token
    // We need to scan through raw content to find where this token appears
    // This is complex because ANTLR strips whitespace and line directives

    // For now, let's use a simpler approach:
    // Track position in raw content and update based on token text

    // Actually, let's use the lineMap to get the file/line for the token's line
    if (tokenLine > 0 && tokenLine <= (int)lineMap.size()) {
      g_loc.currentFile = lineMap[tokenLine - 1].first;
      g_loc.currentLine = lineMap[tokenLine - 1].second;
    }
    g_loc.currentColumn = tokenCol;

    // Determine StartOfLine and LeadingSpace
    // We need to look at the raw text before this token
    // For now, let's approximate based on column position
    if (tokenCol == 1) {
      g_loc.atLineStart = true;
      g_loc.hasLeadingSpace = false;
    } else {
      g_loc.atLineStart = false;
      // Check if there's leading space (column > 1 means there might be)
      g_loc.hasLeadingSpace = (tokenCol > 1);
    }

    print_token(token, tokens, outFile, lexer);
  }
}

