  if (lineEnd == std::string::npos) {
    lineEnd = rawContent.length();
  }
  std::string line = rawContent.substr(pos, lineEnd - pos);
  // Remove trailing \r
  if (!line.empty() && line.back() == '\r') {
    line.pop_back();
  }

  // Check if this is a line directive
  std::regex re2(R"xx(^\s*#\s*(\d+)\s+"([^"]*)".*)xx", std::regex::ECMAScript);
  std::smatch match2;
  if (std::regex_match(line, match2, re2)) {
    currentLine = std::stoi(match2[1].str());
    currentFile = match2[2].str();
  }

  lineMap.push_back({currentFile, currentLine});
  currentLine++;
  pos = lineEnd + 1;
}

