#include <fstream>
#include <iostream>
#include <unordered_map>
#include <regex>
#include <vector>
#include <string>

// Mapping from ANTLR token type to clang token name
std::unordered_map<std::string, std::string> tokenTypeMapping = {
  { "Void", "void" },
  { "Int", "int" },
  { "Const", "const" },
  { "Return", "return" },
  { "If", "if" },
  { "Else", "else" },
